import { RuntimeType } from '@hellodeploy/contracts';

// Node.js LTS version pinned to avoid drift between builds
const NODE_IMAGE = 'node:22-alpine';
// Unprivileged variant: runs as uid 101 and listens on STATIC_PORT instead of 80,
// so static containers never run nginx as root.
const NGINX_IMAGE = 'nginxinc/nginx-unprivileged:1.27-alpine';

/** Container-internal port nginx-unprivileged listens on for static runtimes. */
export const STATIC_PORT = 8080;

/**
 * Generate a safe Dockerfile for the detected runtime.
 * SECURITY: Dockerfiles are always generated by the platform — user Dockerfiles
 * are removed from the build context in `prepareBuildContext`.
 *
 * @param {{ runtimeType: string, buildCommand: string|null, startCommand: string|null, outputDirectory: string|null, applicationPort: number|null }} config
 * @returns {string} Dockerfile content
 */
export function generateDockerfile(config) {
  const { runtimeType, buildCommand, startCommand, outputDirectory, applicationPort } = config;

  switch (runtimeType) {
    case RuntimeType.STATIC:
      return generateStatic();

    case RuntimeType.REACT:
    case RuntimeType.VUE:
      return generateStaticBuild({
        buildCommand: buildCommand ?? 'npm run build',
        outputDirectory: outputDirectory ?? 'dist',
      });

    case RuntimeType.NEXTJS:
      return generateNextjs({ buildCommand: buildCommand ?? 'npm run build' });

    case RuntimeType.EXPRESS:
    case RuntimeType.NODEJS:
      return generateNode({
        startCommand: startCommand ?? 'node server.js',
        applicationPort: applicationPort ?? 3000,
      });

    default:
      throw new Error(`Cannot generate Dockerfile for unsupported runtime: ${runtimeType}`);
  }
}

// ─── Per-runtime templates ─────────────────────────────────────────────────────

function generateStatic() {
  return `FROM ${NGINX_IMAGE}
COPY . /usr/share/nginx/html
EXPOSE ${STATIC_PORT}
CMD ["nginx", "-g", "daemon off;"]
`;
}

function generateStaticBuild({ buildCommand, outputDirectory }) {
  return `FROM ${NODE_IMAGE} AS builder
WORKDIR /app
COPY package*.json ./
RUN npm ci --prefer-offline
COPY . .
RUN ${buildCommand}

FROM ${NGINX_IMAGE}
COPY --from=builder /app/${outputDirectory} /usr/share/nginx/html
EXPOSE ${STATIC_PORT}
CMD ["nginx", "-g", "daemon off;"]
`;
}

function generateNextjs({ buildCommand }) {
  return `FROM ${NODE_IMAGE} AS deps
WORKDIR /app
COPY package*.json ./
RUN npm ci --prefer-offline

FROM ${NODE_IMAGE} AS builder
WORKDIR /app
COPY --from=deps /app/node_modules ./node_modules
COPY . .
RUN ${buildCommand}

FROM ${NODE_IMAGE}
WORKDIR /app
ENV NODE_ENV=production
COPY --from=builder --chown=node:node /app/.next/standalone ./
COPY --from=builder --chown=node:node /app/.next/static ./.next/static
COPY --from=builder --chown=node:node /app/public ./public
USER node
EXPOSE 3000
ENV PORT=3000
CMD ["node", "server.js"]
`;
}

function generateNode({ startCommand, applicationPort }) {
  // Parse the start script to get just the executable and args
  // e.g. "node server.js" → ["node", "server.js"]
  // e.g. "npm start" → ["npm", "start"]
  const parts = startCommand.split(/\s+/).filter(Boolean);
  const cmdJson = JSON.stringify(parts);

  return `FROM ${NODE_IMAGE}
WORKDIR /app
COPY package*.json ./
RUN npm ci --prefer-offline --omit=dev
COPY --chown=node:node . .
USER node
EXPOSE ${applicationPort}
ENV PORT=${applicationPort}
CMD ${cmdJson}
`;
}
